const data = $json;
const lighthouse = data.lighthouseResult || {};
const categories = lighthouse.categories || {};
const audits = lighthouse.audits || {};

const performance_score = Math.round((categories.performance?.score || 0) * 100);
const seo_score = Math.round((categories.seo?.score || 0) * 100);
const accessibility_score = Math.round((categories.accessibility?.score || 0) * 100);

const core_web_vitals = {
  lcp: audits['largest-contentful-paint']?.displayValue || null,
  cls: audits['cumulative-layout-shift']?.displayValue || null,
  tbt: audits['total-blocking-time']?.displayValue || null,
  speed_index: audits['speed-index']?.displayValue || null
};

const technical_issues = [];

if (performance_score < 50) {
  technical_issues.push({ issue: 'Slow page load speed', severity: 'high', description: 'Mobile performance score: ' + performance_score + '/100' });
} else if (performance_score < 80) {
  technical_issues.push({ issue: 'Page load speed could be improved', severity: 'medium', description: 'Mobile performance score: ' + performance_score + '/100' });
}

if (seo_score < 80) {
  technical_issues.push({ issue: 'SEO issues detected', severity: seo_score < 50 ? 'high' : 'medium', description: 'SEO score: ' + seo_score + '/100' });
}

if (accessibility_score < 80) {
  technical_issues.push({ issue: 'Accessibility issues detected', severity: accessibility_score < 50 ? 'high' : 'medium', description: 'Accessibility score: ' + accessibility_score + '/100' });
}

const checkAudits = [
  { key: 'viewport', label: 'Page is not mobile-friendly (no viewport meta tag)' },
  { key: 'image-alt', label: 'Images missing alt text (SEO/accessibility)' },
  { key: 'meta-description', label: 'Missing meta description (SEO)' },
  { key: 'document-title', label: 'Missing or poor page title (SEO)' },
  { key: 'tap-targets', label: 'Touch targets too small on mobile' },
  { key: 'font-size', label: 'Text too small to read on mobile' }
];

checkAudits.forEach(function(item) {
  var audit = audits[item.key];
  if (audit && audit.score !== null && audit.score < 1) {
    technical_issues.push({ issue: item.label, severity: 'medium', description: audit.title });
  }
});

return {
  pagespeed_performance_score: performance_score,
  pagespeed_seo_score: seo_score,
  pagespeed_accessibility_score: accessibility_score,
  pagespeed_mobile_score: performance_score,
  core_web_vitals: core_web_vitals,
  technical_issues: technical_issues
};

const response = $json;
let visual_issues = [];

try {
  const textBlock = (response.content || []).find(function(c) { return c.type === 'text'; });
  const raw = (textBlock && textBlock.text ? textBlock.text : '[]').replace(/```json|```/g, '').trim();
  visual_issues = JSON.parse(raw);
} catch (e) {
  visual_issues = [];
}

return { visual_issues: visual_issues };

const lead = $('Split Out Leads').item.json;
const pagespeed = $('Parse PageSpeed Results').item.json;
const ai = $('Parse AI Vision Response').item.json;
const screenshot = $('Take Screenshot').item.json;

const allIssues = [].concat(pagespeed.technical_issues || [], ai.visual_issues || []);

const severityRank = { high: 3, medium: 2, low: 1 };
allIssues.sort(function(a, b) { return (severityRank[b.severity] || 0) - (severityRank[a.severity] || 0); });

const top_issue = (allIssues[0] && allIssues[0].issue) || 'General website improvements';

const summary = allIssues.length
  ? 'Found ' + allIssues.length + ' issue(s) across visual and technical review. Top priority: ' + top_issue + '.'
  : 'No major issues found.';

return {
  lead_id: lead.id,
  screenshot_url: screenshot.screenshot_url || null,
  pagespeed_performance_score: pagespeed.pagespeed_performance_score,
  pagespeed_seo_score: pagespeed.pagespeed_seo_score,
  pagespeed_accessibility_score: pagespeed.pagespeed_accessibility_score,
  pagespeed_mobile_score: pagespeed.pagespeed_mobile_score,
  core_web_vitals: pagespeed.core_web_vitals,
  visual_issues: ai.visual_issues,
  technical_issues: pagespeed.technical_issues,
  top_issue: top_issue,
  summary: summary
};
